// Inline ColorPicker ΓÇö demonstrates using RunnableWrapper<ColorPicker, Color?> in inline mode.//// NOTE: See https://github.com/gui-cs/clet that turns every Terminal.Gui View into a CLI command// NOTE: ΓÇö typed inputs, a real file picker, a Markdown viewer ΓÇö with consistent JSON output,// NOTE: predictable exit codes, and full keyboard/mouse support. Works for humans and AI agents alike.//// Renders a ColorPicker inline in the terminal (primary buffer) without dialog buttons.// If the user accepts (double-click), the selected color name is written to stdout.// If the user cancels (Esc), nothing is output and exit code is 1.//// Usage://   dotnet run --project Examples/InlineColorPicker//   dotnet run --project Examples/InlineColorPicker -- --initial "#FF0000"//   dotnet run --project Examples/InlineColorPicker -- --initial Red//   $color = dotnet run --project Examples/InlineColorPicker   # capture in shellusing Terminal.Gui.App;using Terminal.Gui.Drawing;using Terminal.Gui.ViewBase;using Terminal.Gui.Views;// Parse command-line argumentsstring? initialValue = null;for (var i = 0; i < args.Length; i++){    if (args [i] is "--initial" or "-i")    {        if (i + 1 < args.Length)        {            initialValue = args [++i];        }        else        {            Console.Error.WriteLine ("Error: --initial requires a color value (e.g., \"#FF0000\" or \"Red\").");            return 1;        }    }}// Enable inline mode before InitApplication.AppModel = AppModel.Inline;IApplication app = Application.Create ().Init ();// Wrap ColorPicker in a RunnableWrapper ΓÇö no dialog buttons, just the picker.// ColorPicker raises Command.Accept on double-click.RunnableWrapper<ColorPicker, Color?> wrapper = new () { Title = "Select a Color (Double-click to accept, Esc to cancel)", ResultExtractor = cp => cp.Value };// Enable color name displaywrapper.GetWrappedView ().Style.ShowColorName = true;wrapper.GetWrappedView ().ApplyStyleChanges ();// Apply initial value via IValue.TrySetValueFromString if providedif (initialValue is { }){    if (!((IValue)wrapper.GetWrappedView ()).TrySetValueFromString (initialValue))    {        Console.Error.WriteLine ($"Error: '{initialValue}' is not a valid color (use e.g., \"#FF0000\" or \"Red\").");        app.Dispose ();        return 1;    }}// Run inline ΓÇö blocks until user accepts or cancelsapp.Run (wrapper);Color? result = wrapper.Result;app.Dispose ();if (result is { } selectedColor){    StandardColorsNameResolver resolver = new ();    string output = resolver.TryNameColor (selectedColor, out string? name) ? name : selectedColor.ToString ();    Console.WriteLine (output);    return 0;}return 1;